// ═══════════════════════════════════════════════════════
// Step 13: Final Report Output
// Erzeugt den vollstaendigen Report als Markdown
// Unterstuetzt mehrere Mitbewerber mit dynamischen Spalten.
// ═══════════════════════════════════════════════════════
const data = $input.all()[0].json;
const config = data.config;
const reportTable = data.reportTable || [];
const summaries = data.summaries || [];
const competitors = data.competitors || [];

// --- Dynamische Tabellen-Spalten ---
const compHeaders = competitors.flatMap(c => [c.short + ' (RAG)', c.short + ' Bewertung']);
const tableHeader = '| Nr | Kategorie | Aspekt | ' + config.ownCompanyShort + ' | ' + compHeaders.join(' | ') + ' |';
const sepCols = ['--', '---------', '------', '-'.repeat(config.ownCompanyShort.length + 2), ...compHeaders.map(h => '-'.repeat(h.length + 2))];
const tableSeparator = '|' + sepCols.join('|') + '|';
const tableRows = reportTable.map(r => {
  const compCells = competitors.flatMap(c => [
    r[c.short] || '',
    r[c.short + '_Bewertung'] || ''
  ]);
  return '| ' + r.Nr + ' | ' + r.Kategorie + ' | ' + r.Aspekt + ' | ' + (r[config.ownCompanyShort] || '') + ' | ' + compCells.join(' | ') + ' |';
}).join('\n');

// --- Zusammenfassungsblock pro Mitbewerber ---
const summaryBlock = summaries.map(s =>
  '### ' + s.competitor + ' (' + s.competitorShort + ')\n\n' +
  '| Metrik | Wert |\n' +
  '|--------|------|\n' +
  '| Verglichene Fakten | ' + s.totalFacts + ' |\n' +
  '| ' + config.ownCompanyShort + ' besser | ' + s.ownBetter + ' |\n' +
  '| ' + s.competitorShort + ' besser | ' + s.competitorBetter + ' |\n' +
  '| Gleichwertig | ' + s.equal + ' |\n' +
  '| Nicht eindeutig | ' + s.unclear + ' |\n'
).join('\n');

const competitorLine = competitors.map(c => c.name + ' (' + c.short + ')').join(', ');
const collectionLine = competitors.map(c => {
  const comp = (config.competitors || []).find(x => x.short === c.short);
  return c.short + ': ' + (comp ? comp.ragCollection : 'N/A');
}).join(', ');

const fullReport =
  '# AVB-Vergleich: ' + config.ownCompanyName + ' vs. ' + competitorLine + '\n\n' +
  '**Erstellt:** ' + data.meta.timestamp + '\n' +
  '**Modell:** ' + data.meta.model + '\n' +
  '**Verglichene Fakten:** ' + reportTable.length + '\n' +
  '**Gesamt-Tokens Synthese:** ' + data.meta.usage.totalTokens + '\n' +
  '**Mitbewerber-Collections:** ' + collectionLine + '\n\n' +
  '---\n\n' +
  '## Zusammenfassung\n\n' + summaryBlock + '\n\n' +
  '---\n\n' +
  '# Executive Summary und Gegenueberstellung\n\n' +
  data.gesamtvergleich + '\n\n' +
  '---\n\n' +
  '# Vergleichstabelle\n\n' +
  tableHeader + '\n' + tableSeparator + '\n' + tableRows + '\n';

// Return individual table rows for XLSX conversion
return reportTable.map(row => ({ json: row }));
